  ('fb5e8fc0-752c-425b-bf2b-0c85ddf12ff7', 'df0f7da9-a558-4d67-99a6-5fa61e2dc49c', 'Construindo a planilhas da Desapropriação (passo a passo)', 'Vamos construir a planilha juntos.', 'https://player-vz-a94806ca-13a.tv.pandavideo.com.br/embed/?v=2b4f5241-58d7-4223-83db-4de9e96c6889', 0, 2, 'aula'),
